**A `debounce` function delays invoking a given function until after a specified wait time has elapsed since the last time it was called, ensuring it only runs once after a burst of calls.**

```javascript
function debounce(func, wait) {
  let timeoutId;
  return function(...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => func.apply(this, args), wait);
  };
}

// Example: Log input value only after user stops typing for 300ms
const input = document.querySelector('input');
input.addEventListener('input', debounce((e) => {
  console.log('Input value:', e.target.value);
}, 300));
```
